@@ -31,8 +44,30 @@ export function verifyActResult(

 export function verifyPrimitiveResult(
 	result: PrimitiveResult,
-	_toolName: string,
-	_goal: string,
-): { stumbled: boolean } {
-	return { stumbled: !result.success };
+	toolName: string,
+	goal: string,
+	sessionId?: string,
+): { stumbled: boolean; learnSignal?: LearnSignal } {
+	const stumbled = !result.success;
+
+	let learnSignal: LearnSignal | undefined;
+	if (stumbled && sessionId) {
+		learnSignal = {
+			kind: "error",
+			goal,
+			agent_name: toolName,
+			details: {
+				agent_name: toolName,
+				goal: `primitive: ${toolName}`,
+				output: result.output,
+				success: result.success,
+				stumbles: 1,
+				turns: 1,
+			},
+			session_id: sessionId,
+			timestamp: Date.now(),
+		};
+	}
+
+	return { stumbled, learnSignal };
 }

